import{_ as a,o,c as t,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"98. Public Holidays","description":"","frontmatter":{"title":"98. Public Holidays","eba":"Mental Health Services 2024-2028","topics":["leave","public-holidays","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/leave/98-public-holidays.md","filePath":"ebas/mental-health/rpn-pen-mho/leave/98-public-holidays.md"}'),n={name:"ebas/mental-health/rpn-pen-mho/leave/98-public-holidays.md"};function i(s,e,l,h,d,p){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="_98-public-holidays" tabindex="-1">98. Public Holidays <a class="header-anchor" href="#_98-public-holidays" aria-label="Permalink to &quot;98. Public Holidays&quot;">​</a></h1><p>Note: For requirements for requests to work on a Public Holiday, see <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/94-rosters.html">clause 94</a> Rosters.</p><p><strong>98.1</strong> An Employee will be entitled to paid time off (or penalty payments for time worked) in respect of public holidays in accordance with this clause.</p><p><strong>98.2</strong> Subject to sub-clause 98.4, the public holidays to which this clause applies are the days determined under Victorian law as public holidays in respect of the following occasions:</p><p><strong>(a)</strong> New Year’s Day, Australia Day, Christmas Day and Boxing Day; and</p><p><strong>(b)</strong> Good Friday, the Saturday immediately before Easter Sunday (Easter Saturday), Easter Sunday, Easter Monday, Anzac Day, King&#39;s Birthday and Labour Day; and</p><p><strong>(c)</strong> Melbourne Cup Day, or in lieu of Melbourne Cup Day, some other day as determined under Victorian law for a particular locality; and</p><p><strong>(d)</strong> The Friday before the AFL Grand Final; and</p><p><strong>(e)</strong> any additional public holiday declared or prescribed in Victoria or a locality in respect of occasions other than those set out in clause 98.2(a) above.</p><p><strong>(f)</strong> If a day or days are not determined in respect of any of the occasions in clause 98.2(a), 98.2(b) 98.2(c) above under Victorian law in any year, the public holiday for that occasion will be the day or date upon which the public holiday was observed in the previous year.</p><p><strong>98.3</strong> Applicability of penalty payments for some public holidays falling on a weekend When Christmas Day, Australia Day, Boxing Day, or New Year&#39;s Day (Actual Day) is a Saturday or a Sunday, and a substitute or additional holiday is determined under Victorian law on another day in respect of any of those occasions (Other Day):</p><p><strong>(a)</strong> Weekend Workers and casual Employees shall receive penalty payments pursuant to sub-clause 98.5 below for time worked on the Actual Day or on the Other Day if the Employee does not work ordinary hours on the Actual Day; and</p><p><strong>(b)</strong> all other Employees will receive penalty payments pursuant to sub-clause 98.5 below for time worked on the Other Day.</p><p><strong>98.4</strong> Substitution of one public holiday for another</p><p><strong>(a)</strong> An Employer and Employee may agree to substitute another day for a day that would otherwise be a public holiday under the Act or this Agreement.</p><p><strong>(b)</strong> An Employer and Employee may agree to substitute another part-day for a part- day that would otherwise be a part-day public holiday under the Act or this Agreement.</p><p><strong>(c)</strong> Where an agreement under subclause (a) or (b) is reached, it will be recorded in writing and a copy given to the Employee.</p><p><strong>98.5</strong> Penalty Payments in respect of public holidays</p><p><strong>(a)</strong> An Employee, other than a casual, who performs work (including overtime work) on a public holiday (or where Christmas Day, Boxing Day, New Year&#39;s Day or Australia Day fall on a weekend, the day to which penalty rates apply pursuant to sub-clause 98.3 above) will be entitled to be paid:</p><p><strong>(i)</strong> 200% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>) for the time worked on a public holiday Monday to Friday; or</p><p><strong>(ii)</strong> 250% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>) for the time worked on a public holiday on a Saturday or Sunday (which is inclusive of the rates in sub-<a href="/eba/ebas/mental-health/rpn-pen-mho/allowances/83-saturday-and-sunday-work.html">clause 83</a>).</p><p><strong>(b)</strong> A casual Employee who performs work (including overtime work) on a public holiday (or where Christmas Day, Boxing Day, New Year&#39;s Day or Australia Day fall on a weekend, the day to which penalty rates apply pursuant to clause 98.3) will be entitled to be paid inclusive of the casual loading;</p><p><strong>(i)</strong> 250% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>) for time worked on a public holiday Monday to Friday; or</p><p><strong>(ii)</strong> 312.5% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>) for time worked on a public holiday on a Saturday or Sunday (which is inclusive of the rates in sub-<a href="/eba/ebas/mental-health/rpn-pen-mho/allowances/83-saturday-and-sunday-work.html">clause 83</a> above).</p><p><strong>98.6</strong> Public Holiday Night Duty</p><p><strong>(a)</strong> Definition of part of a shift For the purposes of this clause &#39;part of a shift&#39; means that period on a public holiday from:</p><p><strong>(i)</strong> midnight to completion of shift; or</p><p><strong>(ii)</strong> commencement of shift to midnight.</p><p><strong>(b)</strong> A night duty Employee is entitled to be paid:</p><p><strong>(i)</strong> The appropriate public holiday rates for each hour worked on that part of a shift that falls on the public holiday; and</p><p><strong>(ii)</strong> At the pro rata public holiday rostered off benefit for that part of a shift that falls on the public holiday that they are not rostered to work and do not work.</p><p>Example: An Employee whose average hours are 0.6EFT is rostered to work from 9.00pm to 7:30am with the shift commencing the day before the public holiday. The hours worked between midnight and 7.30am fall on the public holiday and each of these hours attracts the public holiday rates, e.g. 7.6 hours at the applicable public holiday rate. If the same Employee is not rostered to the night shift that commences on the public holiday, i.e. the shift that commences at 9pm. The period from 9.00pm to midnight attracts a pro rata payment 3 hours x</p><p><strong>0.6</strong> (EFT) hours payable.</p><p><strong>98.7</strong> Accrued days off on public holidays Where a public holiday falls on a day upon which a full-time Employee would ordinarily have been required to be on duty, but the Employee is on an accrued day off, another day will be determined by the Employer to be taken by the Employee in lieu of the public holiday, such day to be within the same work cycle where practical.</p><p><strong>98.8</strong> Public Holiday not required to work Where a public holiday occurs on a day that a part-time or full-time Employee would normally work, but the Employee is not required by the Employer to work on that day, the Employee will be paid an amount equal to the Employee&#39;s ordinary rate of pay for the hours the Employee would normally have worked on that day.</p><p><strong>98.9</strong> Public holidays occurring on rostered days off</p><p><strong>(a)</strong> Subject to sub-clause 98.9(b) and 98.9(c) below, a full-time Employee will receive a sum equal to a day’s ordinary pay for public holidays that occur on their rostered day off.</p><p><strong>(b)</strong> Subject to sub-clause 98.9(c) below, if a public holiday falls on Saturday or Sunday then sub-clause 98.9(a) above will only apply to Weekend Workers.</p><p><strong>(c)</strong> Where on each occasion that Christmas Day, Boxing Day, New Year&#39;s Day or Australia Day falls on a weekend, and under Victorian law an additional day or substitute day (Other Day) applies as a public holiday in respect of that occasion, and:</p><p><strong>(i)</strong> the Employee is rostered off for both the actual day and the Other Day, then only one day&#39;s payment will be made under sub-clause 98.9(a) above; or</p><p><strong>(ii)</strong> the Employee works only on one of either the actual day or the Other Day, and receives penalty rates for the day worked, the Employee will not receive a payment under sub-clause 98.9(a) above in respect of the day not worked.</p><p><strong>98.10</strong> Additional entitlement for part-time Employees rostered off duty NOTE: This clause operates in addition to clause 98.8 for part-time employees. The entitlement to public holiday benefits under this Agreement for a part-time Employee who is rostered off duty on the day on which a public holiday occurs is to be determined as follows:</p><p><strong>(a)</strong> Where on each occasion that Christmas Day, Boxing Day, New Year&#39;s Day or Australia Day falls on a weekend, and under Victorian law an additional day or substitute day (Other Day) applies as a public holiday in respect of that occasion, and:</p><p><strong>(i)</strong> a part-time Employee is not rostered on for both the actual day and the Other Day, then only one day&#39;s payment will be made under this clause; or</p><p><strong>(ii)</strong> a part-time Employee works only on one of either the actual day or the Other Day, and receives penalty rates for the day worked, the part-time Employee will not receive a payment in respect of the day not worked.</p><p><strong>(b)</strong> Where a public holiday occurs on a day a part-time Employee is not rostered to work, the part-time Employee will receive a payment in respect of that public holiday equal to their ordinary pay for the average daily hours worked by that Employee over the previous six months, or their period of employment by the Employer if less than six months Example: Average Shift Length Base Payment Penalty Payment Hours 24 hours 38 hours X 8 hours 5.05 hours T1 5.05 hrs</p><p><strong>(c)</strong> Notwithstanding where otherwise provided, a part-time Employee who is only ever employed between a Monday to Friday, will not receive any entitlement to the Saturday before Easter Sunday.</p><p><strong>98.11</strong> Recall Work on a public holiday A benefit arising from clause 98.8, 98.9 or 98.10will not be diminished where an Employee is required to, and does, perform recall work on that day. For the purpose of this clause only, a Weekend Worker is an Employee who works ordinary hours on a Saturday or Sunday.</p><p><strong>98.12</strong> Substituted Leave - Former Section 97 Employees In lieu of other provisions in this clause, Employees who, as at 19 December 1997, were Employees of the Department and had an entitlement to substituted leave will continue to receive substituted leave in accordance with the following:</p><p><strong>(a)</strong> full-time Employees - who work shift work - will be granted the number of declared public holidays in a year as paid leave of absence regardless of whether the Employee works a public holiday or not.</p><p><strong>(b)</strong> part-time Employees - who work shift work - will be granted a substituted leave day when they work a public holiday in addition to a 50% penalty payment. Alternatively, the Employee may elect not to be granted the substituted leave day but be compensated in lieu thereof by payment of an additional 100%.</p><p>Plain language terms: public holiday pay, holiday pay, PH pay, penalty rates holidays.</p>',52)])])}const c=a(n,[["render",i]]);export{u as __pageData,c as default};
